SELECT [AnalisiCredito-Union].CodiceCliente AS [Codice Cliente], [AnalisiCredito-Union].Name AS [Nome Cliente], [AnalisiCredito-Union].[Name 2] AS [Nome 2], [AnalisiCredito-Union].Address AS Indirizzo, [AnalisiCredito-Union].[Post Code] AS Cap, [AnalisiCredito-Union].City AS Città, [AnalisiCredito-Union].County AS Provincia, [AnalisiCredito-Union].[Country_region Code] AS Paese, [AnalisiCredito-Union].[VAT Registration NO_] AS [Partita Iva], [AnalisiCredito-Union].[Fiscal Code] AS [Cod fiscale], [AnalisiCredito-Union].[Payment Method Code], [AnalisiCredito-Union].[Purchase Group], [AnalisiCredito-Union].[Current Risk], [AnalisiCredito-Union].[Risk Rating], [AnalisiCredito-Union].[PM Failure Assigned Score], [AnalisiCredito-Union].DataAggiornamento, [AnalisiCredito-Union].DataValutazione, [AnalisiCredito-Union].DataScadenza, Val(Format$([AnalisiCredito-Union.datascadenza]-Now(),"#")) AS GiorniScadenza, IIf([AnalisiCredito-Union.Updated Type]=1,"Automatico",IIf([AnalisiCredito-Union.Updated Type]=2,"Manuale","")) AS Aggiornamento, IIf([AnalisiCredito-Union.Skip Credit Info Update]=1,"Sì","No") AS SaltaAggiornamento, IIf([saltaaggiornamento]="No" And Val([giorniscadenza])<Val([forms]![principale]![ControlloNumeroGiorniScadenzaLince]) And ([saldoD]>0 Or [valueoutstandingstagione1]>0 Or [valueoutstandingstagione2]>0),"Sì","No") AS RichiedereControllo, IIf([SaltaAggiornamento]="Sì" And ([saldoD]>0 Or [valueoutstandingstagione1]>0 Or [valueoutstandingstagione2]>0),"Sì","") AS PropostaRipristinoControllo, [AnalisiCredito-Union].SaldoD, [AnalisiCredito-step1-datiSaldoExtraClienti].SaldoDExtra, [SaldoD]+IIf(IsNull([No_])=False,[saldodextra],0) AS SaldoTotale, [AnalisiCredito-Union].[Currency Code], [AnalisiCredito-Union].ValueSoldStagione1, [AnalisiCredito-Union].ValueOutStandingStagione1, [AnalisiCredito-Union].ValueSoldStagione2, [AnalisiCredito-Union].ValueOutStandingStagione2, [AnalisiCredito-Union].ValueReturnStagione1, [AnalisiCredito-Union].ValueReturnStagione2
FROM [AnalisiCredito-Union] LEFT JOIN [AnalisiCredito-step1-datiSaldoExtraClienti] ON [AnalisiCredito-Union].CodiceCliente = [AnalisiCredito-step1-datiSaldoExtraClienti].No_;

